-- compliant: LISTAGG 聚合 + ROWNUM 子查询包装分页 + NVL + IS NULL + 浅分页 + INSERT 不碰自增列
SELECT LISTAGG(NAME, ',') WITHIN GROUP (ORDER BY NAME) FROM ORDERS GROUP BY NAME;
SELECT * FROM (
  SELECT ROWNUM rn, t.* FROM (SELECT ID, NAME FROM ORDERS ORDER BY ID) t WHERE ROWNUM <= 20
) WHERE rn > 10;
SELECT ID, NAME FROM USERS WHERE EMAIL IS NULL AND NVL(STATUS, 0) = 0;
SELECT ID, NAME FROM ORDERS WHERE CREATED_COL < CURRENT_TIMESTAMP ORDER BY ID LIMIT 20 OFFSET 0;
INSERT INTO ORDERS (NAME, AMOUNT) VALUES ('常规业务单', 100.00);
